signatures.label:
({
  children,
  theme = zoraDefaultTheme,
  initialMode = 'light',
}: ZoraProviderProps) => React.JSX.Element

calls.callExpression:
(() => {
    if (children !== undefined) {
      return children;
    }

    if (isSelectionMode) {
      return (
        <Text numberOfLines={1} emphasis="default" variant="label" weight="semiBold">
          {resolveSelectionLabel(resolvedMode)}
        </Text>
      );
    }

    if (title == null && subtitle == null) {
      return null;
    }

    return (
      <Stack gap="xs">
        {title != null ? (
          <Heading ellipsizeMode="tail" level={3} numberOfLines={1} size="h5">
            {title}
          </Heading>
        ) : null}
        {subtitle != null ? (
          <Text ellipsizeMode="tail" numberOfLines={1} emphasis="muted" variant="bodySmall">
            {subtitle}
          </Text>
        ) : null}
      </Stack>
    );
  })
